// Lấy dữ liệu từ node Fetch API (Thay 'Fetch KPI Report' bằng tên node của bạn)
const currentRaw = $( "Fetch KPI Report" ).first().json.body; 

// Lấy dữ liệu từ node Supabase (Thay 'Supabase Select' bằng tên node của bạn)
const historyRaw = $( "daily_kpi_reports" ).all(); 

// Tạo bản sao để tránh lỗi read-only
const current = JSON.parse(JSON.stringify(currentRaw));
const history = JSON.parse(JSON.stringify(historyRaw));

// 1. Tính toán tài chính
const todayRevenue = current.financial?.totalRevenueVnd || 0;
const yesterdayRevenue = history[0]?.json?.financial?.totalRevenueVnd || todayRevenue;
const revenueGrowth = ((todayRevenue - yesterdayRevenue) / (yesterdayRevenue || 1)) * 100;

// 2. So sánh vận hành (On-time Rate)
const todayOTR = current.operations?.onTimeRate || 0;
const historyOTR = history.map(h => h.json?.operations?.onTimeRate || 0);
const avgOTR = historyOTR.length ? historyOTR.reduce((a, b) => a + b, 0) / historyOTR.length : todayOTR;

// 3. Cảnh báo SLA
const todayAlerts = current.summary?.totalSlaAlerts || 0;
const yesterdayAlerts = history[0]?.json?.summary?.totalSlaAlerts || 0;

return {
  report: current,
  analytics: {
    comparison: {
      revenueGrowthPercent: revenueGrowth.toFixed(2),
      otrVsHistory: (todayOTR - avgOTR).toFixed(4),
      alertsChange: todayAlerts - yesterdayAlerts
    },
    historySummary: {
      daysTracked: history.length,
      averageOnTimeRate: avgOTR.toFixed(4)
    }
  },
  contextForAI: {
    insights_from_history: `Doanh thu ${revenueGrowth >= 0 ? 'tăng' : 'giảm'} ${Math.abs(revenueGrowth).toFixed(2)}% so với hôm trước. ` +
                           `Tỷ lệ đúng hạn là ${(todayOTR * 100).toFixed(1)}%, ` +
                           `${todayOTR >= avgOTR ? 'cao hơn' : 'thấp hơn'} trung bình lịch sử (${(avgOTR * 100).toFixed(1)}%).`
  }
};

// Lấy output thô từ AI Agent
const rawOutput = $json.output;

// Hàm trích xuất JSON từ chuỗi văn bản (đề phòng AI trả về text thừa)
function extractJson(text) {
  try {
    // Tìm vị trí bắt đầu { và kết thúc }
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start !== -1 && end !== -1) {
      const jsonStr = text.substring(start, end + 1);
      return JSON.parse(jsonStr);
    }
    throw new Error("Không tìm thấy cấu trúc JSON trong phản hồi của AI.");
  } catch (e) {
    return {
      error: "Lỗi Parse JSON",
      raw: text,
      message: e.message
    };
  }
}

const parsedData = extractJson(rawOutput);

// Trả về dữ liệu đã được làm sạch
return {
  executiveSummary: parsedData["Executive Summary"] || parsedData.executiveSummary,
  risks: parsedData.Risks || parsedData.risks || [],
  recommendations: parsedData.Recommendations || parsedData.recommendations || [],
  fullParsed: parsedData
};

// 1. Lấy dữ liệu từ các node trước đó trong workflow
const apiReport = $("Fetch KPI Report").first().json.body;
const aiAnalysis = $("Parse AI Response").first().json;

// 2. Gom tất cả dữ liệu thành các trường tương ứng chính xác với các cột Supabase
return {
  // Khớp với các cột kiểu dữ liệu TEXT và TIMESTAMPTZ
  generated_at: apiReport.generatedAt,
  report_type: apiReport.reportType,

  // Khớp với các cột kiểu dữ liệu Số (int8, float8, int4)
  total_revenue: apiReport.financial?.totalRevenueVnd || 0,
  on_time_rate: apiReport.operations?.onTimeRate || 0,
  sla_alerts: apiReport.summary?.totalSlaAlerts || 0,

  // Khớp với các cột kiểu dữ liệu JSONB
  // Chúng ta đóng gói các phần nhỏ và kết quả phân tích của AI vào đây để Dashboard Web gọi ra hiển thị
  summary: {
    totalOrdersObserved: apiReport.summary?.totalOrdersObserved,
    totalQuoteRequests: apiReport.summary?.totalQuoteRequests,
    totalNotifications: apiReport.summary?.totalNotifications,
    totalSlaAlerts: apiReport.summary?.totalSlaAlerts,
    totalActionLogs: apiReport.summary?.totalActionLogs
  },

  operations: {
    ordersReceived: apiReport.operations?.ordersReceived,
    ordersDelivered: apiReport.operations?.ordersDelivered,
    ordersFailed: apiReport.operations?.ordersFailed,
    averageDeliveryMinutes: apiReport.operations?.averageDeliveryMinutes,
    onTimeRate: apiReport.operations?.onTimeRate,
    averageSlaMarginMinutes: apiReport.operations?.averageSlaMarginMinutes,
    routeBandStats: apiReport.routeBandStats // Đẩy thống kê tuyến vào đây luôn để Web vẽ biểu đồ
  },

  financial: {
    totalRevenueVnd: apiReport.financial?.totalRevenueVnd,
    averageOrderValueVnd: apiReport.financial?.averageOrderValueVnd,
    automationRoiPercent: apiReport.financial?.automationRoiPercent,
    automationNetBenefitVnd: apiReport.financial?.automationNetBenefitVnd,
    // Đút kèm đống Executive Summary, Risks, Recommendations từ AI vào object tài chính/vận hành tổng thể
    aiInsights: {
      executiveSummary: aiAnalysis.executiveSummary,
      risks: aiAnalysis.risks,
      recommendations: aiAnalysis.recommendations
    }
  },

  // Khớp cột raw_data (jsonb) - Lưu nguyên bản dữ liệu API để dự phòng
  raw_data: apiReport
};

